import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import type { FileUploaderListProps } from './FileUploaderList.types';
import { FileUploaderListItem } from './FileUploaderListItem';

export const FileUploaderList: FC<FileUploaderListProps> = ({ files, onRemove, onRefresh, className, ...props }) => {
	if (!files?.length) {
		return null;
	}

	return (
		<div
			data-testid="FileUploaderList"
			className={classNames('dsb_file-uploader-file-list', className)}
			role="list"
			{...props}
		>
			{files.map((file, index) => {
				const { name, state = 'upload', type, ...rest } = file;

				return (
					<FileUploaderListItem
						key={index}
						name={name}
						state={state}
						onRefresh={onRefresh}
						onRemove={onRemove}
						type={type}
						{...rest}
					/>
				);
			})}
		</div>
	);
};
